fixes.helper_function:
// Add at module level (below imports, before class definitions)
function getErrorKind(error: unknown): string {
  if (error instanceof InvalidArgumentsError) return "InvalidArgumentsError"
  if (error instanceof ToolError) return "ToolError"
  if (error instanceof TimeoutError) return "TimeoutError"
  if (error instanceof TransientError) return "TransientError"
  if (error instanceof ValidationError) return "ValidationError"
  return "UnknownError"
}

